def parse_duration(s: str) -> int:
    """
    Преобразует строку с продолжительностью вида '2h30m', '45m', '1h', '90s' в количество секунд.
    Поддерживаемые единицы: h (часы), m (минуты), s (секунды).
    При невалидном вводе выбрасывает ValueError.
    """
    if not s or not isinstance(s, str):
        raise ValueError("Невалидный ввод: пустая строка или не строка")

    total_seconds = 0
    i = 0
    num = ""

    while i < len(s):
        char = s[i]
        if char.isdigit():
            num += char
        elif char in 'hms':
            if not num:
                raise ValueError("Невалидный формат: отсутствует число перед единицей измерения")
            value = int(num)
            if char == 'h':
                total_seconds += value * 3600
            elif char == 'm':
                total_seconds += value * 60
            elif char == 's':
                total_seconds += value
            num = ""
        else:
            raise ValueError(f"Невалидный символ: {char}")
        i += 1

    if num:
        raise ValueError("Строка не заканчивается единицей измерения")

    return total_seconds
